template-STD_REG.scripts:
			var RS;

function PosOnLoad()
{   
  RS=Ctrl("main").GetLastDocXML("d_reporte");
  EnableControls();
}


function EnableControls()
{      
if (Ctrl("d_reporte").GetXValue()!="")         
{          
	if(RS.FindElement2("option","value",Ctrl("d_reporte").GetXValue()).GetAttr("impl")=="M")
	{
		Ctrl("l_eva2").SetEnabled(true);
		Ctrl("l_eva3").SetEnabled(true);
		Ctrl("l_pree").SetEnabled(true);
		Ctrl("l_eva360").SetEnabled(true);
	} else
	{
		Ctrl("l_eva2").SetXValue("0"); Ctrl("l_eva2").SetEnabled(false);
		Ctrl("l_eva3").SetXValue("0"); Ctrl("l_eva3").SetEnabled(false);
		Ctrl("l_pree").SetXValue("0"); Ctrl("l_pree").SetEnabled(false);
		Ctrl("l_eva360").SetXValue("0"); Ctrl("l_eva360").SetEnabled(false);
	} 
} else
{
	Ctrl("l_eva2").SetXValue("0"); Ctrl("l_eva2").SetEnabled(false);
	Ctrl("l_eva3").SetXValue("0"); Ctrl("l_eva3").SetEnabled(false);
	Ctrl("l_pree").SetXValue("0"); Ctrl("l_pree").SetEnabled(false);     
	Ctrl("l_eva360").SetXValue("0"); Ctrl("l_eva360").SetEnabled(false);
}                       
}
